const axios = require('axios');
const fs = require('fs');
const path = require('path');

const API_KEY = process.env.PREMBLY_API_KEY;
const API_URL = 'https://api.prembly.com/api/v1/checker-widget/sdk/sessions/';
const LOG_FILE = path.join(__dirname, 'output.log');

async function pollSessions() {
    if (!API_KEY) {
        console.error('PREMBLY_API_KEY environment variable is not set.');
        process.exit(1);
    }

    try {
        const response = await axios.get(API_URL, {
            headers: {
                'x-api-key': API_KEY,
                'Accept': 'application/json'
            }
        });

        // The response structure might vary based on the actual API response.
        // Usually, it's an array or an object containing an array.
        // Based on the requirement to count total sessions:
        const sessions = response.data.data || response.data;
        const count = Array.isArray(sessions) ? sessions.length : 0;

        const logMessage = `Total sessions: ${count}\n`;
        fs.writeFileSync(LOG_FILE, logMessage);
        console.log(`Successfully polled sessions. ${logMessage.trim()}`);

    } catch (error) {
        const errorMessage = `Error fetching sessions: ${error.message}\n`;
        fs.writeFileSync(LOG_FILE, errorMessage);
        console.error(errorMessage.trim());
        process.exit(1);
    }
}

pollSessions();

