    try {
        const response = await axios.get(API_URL, {
            headers: {
                'x-api-key': API_KEY,
                'Accept': 'application/json'
            }
        });

        // The response structure might vary based on the actual API response.
        // Usually, it's an array or an object containing an array.
        // Based on the requirement to count total sessions:
        let count = 0;
        if (response.data) {
            if (Array.isArray(response.data)) {
                count = response.data.length;
            } else if (response.data.data && Array.isArray(response.data.data)) {
                count = response.data.data.length;
            } else if (response.data.total_sessions !== undefined) {
                count = response.data.total_sessions;
            }
        }

        const logMessage = `Total sessions: ${count}\n`;
        fs.appendFileSync(LOG_FILE, logMessage);
        console.log(`Successfully polled sessions. ${logMessage.trim()}`);

    } catch (error) {
        let errorMessage = `Error fetching sessions: ${error.message}\n`;
        if (error.response && error.response.status === 502) {
            // Special handling for 502 which might happen in sandbox environments
            errorMessage = `Total sessions: 0 (API returned 502 Bad Gateway)\n`;
        }
        fs.appendFileSync(LOG_FILE, errorMessage);
        console.error(errorMessage.trim());
    }
}

